-- 2. Agregar columnas faltantes si no existen
ALTER TABLE campaigns ADD COLUMN IF NOT EXISTS type text DEFAULT 'nueva_campana';
ALTER TABLE campaigns ADD COLUMN IF NOT EXISTS status text DEFAULT 'activa';
ALTER TABLE campaigns ADD COLUMN IF NOT EXISTS objective text;
ALTER TABLE tasks ADD COLUMN IF NOT EXISTS campaign_id uuid REFERENCES campaigns(id) ON DELETE SET NULL;
ALTER TABLE tasks ADD COLUMN IF NOT EXISTS etapa text;

-- 3. Re-agregar constraints correctos
ALTER TABLE campaigns ADD CONSTRAINT campaigns_status_check CHECK (status IN ('activa','pausada','desactivada'));
ALTER TABLE campaigns ADD CONSTRAINT campaigns_type_check CHECK (type IN ('nueva_campana','iteracion','refresh','bombero'));

-- 4. Limpiar tareas y campañas
